    /// "On the spot edition" or "Standard Copy" followed by
    /// "<nn> Modifiers"
    pub fn label(&self) -> cxx::UniquePtr<crate::ffi::TCollection_AsciiString> {
        crate::ffi::IFSelect_TransformStandard_label(self)
    }

